import{_ as p,o as k,c as P,ag as t}from"./chunks/framework.ETe_P6d1.js";const j="/kaiping-reports/assets/8.C23Cr4Eg.jpg",c="/kaiping-reports/assets/6.DsWu_Tm7.jpg",a="/kaiping-reports/assets/1.XW1tJSW8.jpg",x="/kaiping-reports/assets/2.5boHcLZA.png",K="/kaiping-reports/assets/3.D3ghvos2.jpg",H="/kaiping-reports/assets/4.CSlo92a_.jpg",n="/kaiping-reports/assets/5.C215vp9q.jpg",S="/kaiping-reports/assets/7.gh6mC73g.jpg",e=JSON.parse('{"title":"开平立园泮立楼建筑材料构造与装饰文化调研报告","description":"","frontmatter":{"title":"开平立园泮立楼建筑材料构造与装饰文化调研报告"},"headers":[],"relativePath":"reports/郑茹涵/郑茹涵_调研报告.md","filePath":"reports/郑茹涵/郑茹涵_调研报告.md"}'),r={name:"reports/郑茹涵/郑茹涵_调研报告.md"};function V(O,A,W,R,q,U){return k(),P("div",null,[...A[0]||(A[0]=[t('<h3 id="开平立园泮立楼建筑材料构造与装饰文化调研报告" tabindex="-1">开平立园泮立楼建筑材料构造与装饰文化调研报告 <a class="header-anchor" href="#开平立园泮立楼建筑材料构造与装饰文化调研报告" aria-label="Permalink to &quot;开平立园泮立楼建筑材料构造与装饰文化调研报告&quot;">​</a></h3><p>考察地点：广东省江门市开平市立园・泮立楼</p><p>考察时间：2026 年 4 月 1 日</p><p>学生姓名：郑茹涵</p><p>指导教师：石拓</p><p>一、引言</p><p>1.1调研背景</p><p>泮立楼位于广东省江门市开平市塘口镇立园内部，是旅美华侨谢维立于1926—1936年间兴建的私家别墅建筑，为立园六大主楼中形制最完整、装饰最精美、中西合璧特征最突出的一栋。楼名取其父谢圣泮之“泮”与本人之名“立”相合，既体现家族伦理，也寄托华侨“荣归故里、光耀门庭”的价值追求。</p><p>20世纪20—30年代，五邑侨乡社会动荡、匪患频发，同时西风东渐，海外华侨带回西方建筑技术与生活方式，促使侨乡民居出现“防御性+居住性+西洋审美”的复合形态。泮立楼正是这一时代背景下的典型产物：以钢筋混凝土实现坚固防御，以岭南传统工艺延续文化根脉，以西洋柱式、装饰纹样表达现代审美，形成结构、材料、装饰三重层面的中西融合[1]。</p><p>2007年，“开平碉楼与村落”列入《世界文化遗产名录》，泮立楼作为立园核心建筑，成为研究近代侨乡建筑、中西建筑文化交融、岭南民居近代化转型的重要实物样本。本次课程调研即以泮立楼为对象，重点围绕维度二：建筑材料与构造技术、维度三：装饰符号与文化表达展开系统分析，形成完整学术调研报告。</p><p>1.2调研目的</p><p>1.系统梳理泮立楼主体结构、围护墙体、屋面、门窗等部位的材料类型、组合方式与构造做法，总结其技术特征与地域适应性。</p><p>2.解析泮立楼立面造型、雕刻纹样、色彩体系、家具陈设中的装饰符号系统，揭示中西文化并置与融合的内在逻辑。</p><p>3.结合文献与现场观察，建立“材料—构造—装饰—文化”的分析链条，理解侨乡建筑“技术西化、文化守根”的整体特征。</p><p>1.3调研对象与范围</p><p>调研对象：开平立园泮立楼单体建筑。</p><p>调研范围：建筑外观、立面材质、梁柱结构、屋面构造、门窗细部、灰塑木雕、室内装饰、色彩搭配等。</p><p>二、泮立楼建筑材料与构造技术分析</p><p>2.1 主体结构材料与体系特征</p><p>泮立楼为三层半钢筋混凝土框架结构，是20世纪初侨乡建筑中技术水平较高的一类。与同期广府民居普遍采用的砖木结构不同，泮立楼以混凝土为主体承重体系，体现出明显的近代化、技术西化倾向。</p><p><img src="'+j+`" alt="图8：泮立楼结构"></p><pre><code>              1.jpg
</code></pre><p>2.1.1 结构材料：钢筋混凝土的本土化应用</p><p>主体梁柱、楼板、楼梯、阳台均采用现浇钢筋混凝土，水泥多从英国、香港进口，钢筋为进口圆钢，现场绑扎后整体浇筑[1]。这一做法具有三重意义：</p><ol><li>防御功能：混凝土整体性强、抗冲击、防凿挖，适应侨乡防盗防匪的社会需求。2. 气候适应：混凝土耐潮、耐风雨、抗台风，适配岭南高温多雨气候。3. 身份象征：进口材料与现代技术在当时属于昂贵稀缺资源，成为华侨经济实力与现代视野的物质表达。</li></ol><p><img src="data:image/jpeg;base64," alt="a69c47eda24bf7e727943a28ede8be42"></p><p>2.jpg</p><p>框架结构使墙体不再承担主要承重，仅起围护与分隔作用，为大窗、阳台、连续拱廊等西洋立面形式提供结构可能，实现“结构决定形式”的近代建筑逻辑。</p><p>2.1.2 辅助结构：砖木材料的传统延续</p><p>在非承重部位，泮立楼仍大量使用砖木材料，形成“混凝土主结构+砖木次结构”的混合体系：</p><p>• 室内隔墙、天花龙骨、装饰挂落采用杉木、樟木等本地木材；</p><p>• 局部围护墙采用红砖砌筑+水泥砂浆抹面，兼顾经济性与施工习惯；</p><p>• 家具、楼梯扶手、门窗框以硬木制作，延续广府民居木作传统。</p><p>这种混合并非技术落后，而是理性选择：混凝土解决安全与耐久，木材解决舒适与温度，砖材解决经济与习惯，三者互补，构成侨乡建筑典型的“技术折中”构造模式[2]。</p><p>2.2 围护体系材料与立面构造</p><p>2.2.1 外墙材料：水洗石米与抹灰工艺</p><p>泮立楼外墙主体采用水洗石米（洗石米）饰面，为民国时期岭南西洋式建筑最具代表性的外墙工艺：以水泥为胶结料，混合天然河石、碎石，浇筑抹平后在初凝前水洗，露出石子肌理，质感细腻、颜色柔和、耐污耐雨。其构造层次由内至外大致为：1. 红砖或混凝土基层、2. 水泥砂浆找平层、3.石米水泥面层、4. 水洗露石处理。该工艺兼具西方近代饰面技术与地方材料，造价高于普通抹灰，却低于整块石材，成为侨乡别墅“体面而经济”的优选做法。</p><p><img src="data:image/jpeg;base64," alt="96de6ccccf4590b8ec9dc378669e33ca"></p><p>3.jpg</p><p>2.2.2 墙角、线脚：石材与混凝土仿石构造</p><p>建筑转角、窗套、柱础、檐口线脚采用混凝土预制线条+局部石材，模仿西方古典建筑石作效果。线条层次分明、比例严谨，强化立面竖向与横向划分，使建筑呈现庄重典雅的西洋古典气质。构造上以预埋铁件+水泥砂浆粘贴固定，线条与墙体整体连接，抗风抗震性能良好。</p><p>2.3 屋面材料与屋顶构造</p><p>泮立楼屋顶采用中式传统形制+现代构造技术的组合，是维度二最具代表性的融合点。屋面铺设广东佛山绿琉璃瓦，釉色均匀、排水顺畅、耐久性强，为岭南祠堂、宅第等高等级建筑的传统用材。琉璃瓦不仅防水隔热，更以色彩象征身份与礼制，体现园主对中国传统等级文化的认同。</p><p>屋顶构造：中式坡屋顶+混凝土基层。与传统民居纯木构屋顶不同，泮立楼以混凝土板替代木屋架，防火、防腐、防蚁，安全性显著提升；同时保留琉璃瓦坡屋顶外观，实现“构造西化、形象传统”[3]。檐部采用飞檐起翘，脊饰以灰塑卷草、瑞兽，延续岭南屋顶装饰传统；檐下混凝土线脚则模仿西方檐口，中西并置而视觉协调。</p><p><img src="data:image/jpeg;base64," alt="951e1af839983862dc374598990f32d9"></p><p>4.jpg</p><p>2.4 门窗构造与材料技术</p><p>泮立楼窗户为钢筋混凝土窗套+拱券造型+多层窗扇构造：</p><p>• 外层：铁窗花/铁栅，防盗防御；</p><p>• 中层：玻璃木窗，采光通风；</p><p>• 内层：木百叶或纱扇，遮阳防蚊。</p><p>窗洞上方多做半圆拱或平拱，为西方古典建筑常见形式；窗套线脚厚重、比例严谨，强化立面秩序感。材料上以混凝土定型、木材作扇、铁件防护，形成复合功能构造。</p><p>入口大门采用硬木实拼门，纹理厚重、雕刻简洁；门锁、合页多为进口铜铁五金，做工精细，体现近代侨宅“外固内奢”的特点。门框以混凝土或石材加固，防撬防撞，兼顾安全与耐久。</p><p>三、泮立楼装饰符号与文化表达分析（维度三）</p><p>3.1 立面造型符号：中西形制的拼贴与融合</p><p>泮立楼的装饰首先体现在建筑形制语言层面，形成“中国屋顶+西方屋身”的经典侨乡构图。</p><p>屋顶采用重檐意象、琉璃瓦、正脊、垂脊、灰塑脊饰，属典型广府高等级民居符号：</p><p>• 绿色琉璃：象征清雅、尊贵，区别于普通民居灰瓦；</p><p>• 脊饰瑞兽、卷草：寓意驱邪纳吉、家族兴旺；</p><p>• 飞檐翘角：表达岭南建筑轻盈灵动的审美传统。</p><p>屋顶在视觉上“压住”整栋建筑，使西洋屋身不脱离中国文化母体，构成文化身份的视觉锚点。</p><p>立面二层、三层设置连续柱廊与拱券，柱式简化模仿西方古典秩序：柱身挺拔、柱头有卷草与花叶装饰，檐口线脚分层，强调水平韵律与竖向支撑。</p><p>这类符号源自欧洲古典建筑与殖民地建筑，传递理性、秩序、现代、文明的意象，是华侨对西方生活方式与现代文明的认同表达[2]。二者叠加，形成泮立楼最核心的文化表达：身体面向现代世界，精神回归中华传统。</p><p><img src="data:image/jpeg;base64," alt="be6fdd40b8856f5e94969dfe660cb020"><img src="data:image/jpeg;base64," alt="0ae4eefffac1c926db3707a9e9a31f84"></p><pre><code>                                  6.jpg
</code></pre><p>3.2 雕刻装饰符号：灰塑、木雕与叙事文化</p><p>泮立楼装饰以灰塑、木雕为核心，题材高度传统，是维度三文化内涵最集中的部分。建筑外墙多处设岭南灰塑，题材以传统戏曲、历史人物为主，如“三顾茅庐”“八仙贺寿”等。</p><p><img src="data:image/jpeg;base64," alt="ad2d29c6713c9928859e343484b04dc0"></p><pre><code>            7.jpg
</code></pre><p>厅内隔断、花罩、屏风采用潮州金漆木雕，题材多为“六国大封相”“花鸟瑞兽”“缠枝莲”等。木雕构成室内空间的文化核心，使西洋结构的房子内部仍保持中式礼制空间与审美氛围。</p><p><img src="`+c+`" alt="图6：装饰细节"></p><pre><code>             8.jpg
</code></pre><p>3.3 色彩符号：淡雅基调与等级点缀</p><p>泮立楼色彩体系呈现中西调和、雅而不艳的特点。墙面主色：米黄、浅灰石米，温和耐看，适配岭南强光，属近代西洋建筑常用中性色；屋顶强调色：翠绿琉璃，鲜明醒目，为中国传统高等级色彩；装饰重点色：木雕金箔、灰塑红/蓝/绿小面积点缀，富贵而不俗。色彩策略体现双重审美：以西方现代色彩学控制整体协调，以中国传统色彩象征等级与吉祥。</p><p>四、调研结论</p><p>本次调研以开平立园泮立楼为对象，严格围绕建筑材料与构造（维度二）、装饰符号与文化表达（维度三）展开系统分析，形成如下结论：</p><p>第一，在材料与构造层面，泮立楼以钢筋混凝土框架为核心结构，结合砖木围护、水洗石米外墙、琉璃瓦坡屋顶，形成“近代技术+传统材料”的混合体系。其构造逻辑以防御、耐候、耐久、舒适为导向，技术上向西学习，材料上就地取材，体现侨乡建筑高度的实用理性与地域适应性。</p><p>第二，在装饰与文化层面，泮立楼建立了“中式屋顶+西式屋身、传统题材+西洋形制、伦理叙事+现代审美”的复合符号系统。灰塑、木雕承载儒家伦理与吉祥文化，柱式、拱券、壁炉表达现代文明认同，色彩与陈设实现中西审美调和，最终完成华侨文化身份与价值观念的空间表达。</p><p>第三，从整体看，泮立楼并非简单“中西拼贴”，而是功能、技术、文化三者统一的有机整体：材料构造解决生存与安全，装饰符号解决文化认同与精神归属，共同构成近代五邑侨乡建筑的典型范式，具有重要的建筑史、文化史与遗产保护研究价值。</p><p>本次调研通过现场观察与文献互证，清晰呈现了泮立楼“技术近代化、文化本土化”的基本特征，为理解岭南侨乡建筑、传统与现代融合设计提供了真实、具体、可借鉴的实物案例，达到课程调研预期目标。</p><p>五、附录：调研记录</p><p>5.1摄影记录：</p><p>图一、泮立楼正立面图</p><p>图二、楼梯正面图</p><p>图三、外墙墙面图</p><p>图四、泮立楼屋顶图</p><p>图五、窗户细节图</p><p>图六、欧式柱子与拱券图</p><p>图七、泮立楼墙面装饰图</p><p>图八、泮立楼金漆木雕图片</p><p>5.2文献资料：</p><p>参考书目：</p><p>[1] 广东省文物考古研究所. 开平碉楼[M]. 北京：文物出版社，2007.</p><p>[2] 张复合. 中国近代建筑史研究[M]. 北京：清华大学出版社，2011.</p><p>[3] 华南理工大学建筑学院. 开平碉楼与村落保护研究[M]. 广州：华南理工大学出版社，2018.</p><hr><h2 id="附录-调研图片记录" tabindex="-1">附录：调研图片记录 <a class="header-anchor" href="#附录-调研图片记录" aria-label="Permalink to &quot;附录：调研图片记录&quot;">​</a></h2><p>本报告共插入8张现场照片：</p><p><img src="`+a+'" alt="图1：泮立楼外观"></p><p><img src="'+x+'" alt="图2：泮立楼立面细节"></p><p><img src="'+K+'" alt="图3：建筑材料分析"></p><p><img src="'+H+'" alt="图4：构造细节"></p><p><img src="'+n+'" alt="图5：装饰符号"></p><p><img src="'+c+'" alt="图6：室内空间"></p><p><img src="'+S+'" alt="图7：建筑构件"></p><p><img src="'+j+'" alt="图8：泮立楼全景"></p>',106)])])}const G=p(r,[["render",V]]);export{e as __pageData,G as default};
